// Rise 6.0 - reading health from S1C metadata:
if (event.getPacket() instanceof S1CPacketEntityMetadata) {
    S1CPacketEntityMetadata s1c = (S1CPacketEntityMetadata) event.getPacket();
    Entity entity = mc.theWorld.getEntityByID(s1c.getEntityId());
    if (entity instanceof EntityLivingBase && entity == killauraTarget) {
        for (DataWatcher.WatchableObject obj : s1c.getWatchedObjects()) {
            // Index 6 for living entities = health
            if (obj.getDataValueId() == 6) {
                float health = (Float) obj.getObject();
                targetHealth = health;
            }
            // Index 0 = entity flags (sprinting, on fire, etc.)
            if (obj.getDataValueId() == 0) {
                byte flags = (Byte) obj.getObject();
                targetSprinting = (flags & 8) != 0;  // bit 3 = sprinting
            }
        }
    }
}
// Vanilla S1CPacketEntityMetadata:
public class S1CPacketEntityMetadata implements Packet<INetHandlerPlayClient> {
    private int entityId;
    private List<DataWatcher.WatchableObject> metadata;
    public S1CPacketEntityMetadata() {}
    public S1CPacketEntityMetadata(int idIn, DataWatcher watcherIn, boolean b) {
        this.entityId = idIn;
        this.metadata = watcherIn.getAllWatched();
    }
    public void processPacket(INetHandlerPlayClient h) { h.handleEntityMetadata(this); }
    public int getEntityId() { return this.entityId; }
    public List<DataWatcher.WatchableObject> getWatchedObjects() { return this.metadata; }
}
